//

function StyleHandle(mouse, data) {
    let manager = this,
        { chart, options } = manager,
        { highlightElement, legendInstance } = options,
        { ranges, colorScale } = legendInstance.component.brushOptions,
        point = data.point,
        color;

    if (ranges && ranges.length) {
        let colors = chart.seriesColor;
        color = colors[point % colors.length];
    } else {
        color = colorScale(point.data);
    }

    highlightElement.style('fill', color);
}

export { StyleHandle };
